interface Repository<T, ID> {
    Optional<T> findById(ID id);
    List<T> findAll();
    T save(T entity);
    void delete(T entity);
    long count();
    default boolean exists(ID id) { return findById(id).isPresent(); }
}
class Student {
    int id; String name;
    Student(int i, String n) { id=i; name=n; }
    public String toString() { return name; }
}
class StudentRepository implements Repository<Student, Integer> {
    private Map<Integer, Student> store = new HashMap<>();
    public Optional<Student> findById(Integer id) { return Optional.ofNullable(store.get(id)); }
    public List<Student> findAll() { return new ArrayList<>(store.values()); }
    public Student save(Student s) { store.put(s.id, s); return s; }
    public void delete(Student s)  { store.remove(s.id); }
    public long count()            { return store.size(); }
}
public class App {
    public static void main(String[] args) {
        StudentRepository repo = new StudentRepository();
        repo.save(new Student(1, "Aisha"));
        repo.save(new Student(2, "Raj"));
        repo.save(new Student(3, "Priya"));
        System.out.println("Saved " + repo.count() + " students");
        System.out.println("Found: " + repo.findById(1).get());
        System.out.println("Exists 1: " + repo.exists(1) + " | Exists 99: " + repo.exists(99));
        System.out.println("Count: " + repo.count());
    }
