import java.util.*;
interface Ranked<T extends Comparable<T>> {
    List<T> rank(List<T> items);  // sorted descending
}
class IntegerRanker implements Ranked<Integer> {
    public List<Integer> rank(List<Integer> items) {
        List<Integer> sorted = new ArrayList<>(items);
        sorted.sort((a, b) -> Integer.compare(b, a));  // descending
        return sorted;
    }
}
public class App {
    public static void main(String[] args) {
        Ranked<Integer> ranker = new IntegerRanker();
        List<Integer> scores = Arrays.asList(85, 92, 78, 95, 68, 88);
        System.out.println("Ranked: " + ranker.rank(scores));
    }
}

import java.util.*;
interface PricingStrategy<T> { double calculatePrice(T item); }
class Product { String name; double basePrice; Product(String n, double p) { name=n; basePrice=p; } }
class RegularPrice implements PricingStrategy<Product> {
    public double calculatePrice(Product p) { return p.basePrice; }
}
class DiscountedPrice implements PricingStrategy<Product> {
    public double calculatePrice(Product p) { return Math.round(p.basePrice * 0.9 * 10.0) / 10.0; }
}
public class App {
    static void showPricing(Product p, PricingStrategy<Product> strategy) {
        System.out.printf("%s: ₹%.1f%n", strategy.getClass().getSimpleName().replace("Price",""), strategy.calculatePrice(p));
    }
    public static void main(String[] args) {
        List<Product> products = Arrays.asList(new Product("Mouse",799), new Product("Keyboard",1999));
        PricingStrategy<Product> regular    = new RegularPrice();
        PricingStrategy<Product> discounted = new DiscountedPrice();
        for (Product p : products) {
            System.out.println("Regular: ₹" + regular.calculatePrice(p));
            System.out.println("Discounted: ₹" + discounted.calculatePrice(p));
        }
    }
}

