import java.util.*;
@FunctionalInterface interface Validator<T> { boolean isValid(T item); String message = ""; }
// Actually simpler:
interface NamedValidator<T> {
    boolean isValid(T item);
    String message();
}
public class App {
    static <T> List<String> validate(T item, List<NamedValidator<T>> validators) {
        List<String> errors = new ArrayList<>();
        for (NamedValidator<T> v : validators) {
            if (!v.isValid(item)) errors.add(v.message());
        }
        return errors;
    }
    public static void main(String[] args) {
        List<NamedValidator<String>> rules = Arrays.asList(
            new NamedValidator<String>() {
                public boolean isValid(String s) { return s != null && !s.isBlank(); }
                public String message() { return "Must not be blank"; }
            },
            new NamedValidator<String>() {
                public boolean isValid(String s) { return s != null && s.length() >= 5; }
                public String message() { return "Must be at least 5 chars"; }
            }
        );
        System.out.println("'hello world' errors: " + validate("hello world", rules));
        System.out.println("'' errors: "           + validate("", rules));
        System.out.println("'hi' errors: "         + validate("hi", rules));
    }
}

