import java.util.*;
import java.util.stream.*;
interface Mapper<S, T> {
    T mapTo(S source);
    S mapFrom(T target);
    default List<T> mapAllTo(List<S> sources) {
        return sources.stream().map(this::mapTo).collect(Collectors.toList());
    }
}
class Employee { int id; String name; double salary;
    Employee(int i, String n, double s) { id=i; name=n; salary=s; }
    public String toString() { return "[id=" + id + ", name=" + name + ", salary=" + salary + "]"; }
}
class EmployeeDto { String name, formattedSalary;
    EmployeeDto(String n, String f) { name=n; formattedSalary=f; }
    public String toString() { return name + " | " + formattedSalary; }
}
class EmployeeMapper implements Mapper<Employee, EmployeeDto> {
    public EmployeeDto mapTo(Employee e) {
        return new EmployeeDto(e.name, String.format("₹%,d", (int)e.salary));
    }
    public Employee mapFrom(EmployeeDto dto) {
        double salary = Double.parseDouble(dto.formattedSalary.replaceAll("[₹,]", ""));
        return new Employee(0, dto.name, salary);
    }
}
public class App {
    public static void main(String[] args) {
        EmployeeMapper mapper = new EmployeeMapper();
        Employee e1 = new Employee(1, "Aisha", 95000);
        System.out.println("To DTO: " + mapper.mapTo(e1));
        System.out.println("From DTO: " + mapper.mapFrom(new EmployeeDto("Priya", "₹85,000")));
        List<Employee> staff = Arrays.asList(new Employee(1,"Aisha",95000), new Employee(2,"Raj",72000));
        System.out.println("All DTOs: " + mapper.mapAllTo(staff));
    }
}

