import java.util.*;
import java.util.stream.*;
interface Repository<T, ID> {
    Optional<T> findById(ID id);
    List<T> findAll();
    T save(T entity);
    void delete(T entity);
    long count();
}
class Product { String id, name, category; double price;
    Product(String i, String n, String c, double p) { id=i; name=n; category=c; price=p; }
    public String toString() { return name; }
}
class ProductRepository implements Repository<Product, String> {
    private Map<String, Product> store = new HashMap<>();
    public Optional<Product> findById(String id) { return Optional.ofNullable(store.get(id)); }
    public List<Product> findAll()  { return new ArrayList<>(store.values()); }
    public Product save(Product p)  { store.put(p.id, p); return p; }
    public void delete(Product p)   { store.remove(p.id); }
    public long count()             { return store.size(); }

    // Domain-specific:
    public List<Product> findByCategory(String cat) {
        return store.values().stream()
            .filter(p -> p.category.equals(cat))
            .sorted(Comparator.comparing(p -> p.name))
            .collect(Collectors.toList());
    }
    public List<Product> findExpensive(double minPrice) {
        return store.values().stream()
            .filter(p -> p.price > minPrice)
            .collect(Collectors.toList());
    }
}
public class App {
    public static void main(String[] args) {
        ProductRepository repo = new ProductRepository();
        repo.save(new Product("P01","Mouse",    "Electronics", 799));
        repo.save(new Product("P02","Keyboard", "Electronics", 1999));
        repo.save(new Product("P03","Java Book","Books",        649));
        System.out.println("All: " + repo.count() + " products");
        System.out.println("Electronics: " + repo.findByCategory("Electronics"));
        System.out.println("Expensive (>₹1000): " + repo.findExpensive(1000));
    }
}

@FunctionalInterface
interface Pipeline<T> {
    T process(T input);
    default Pipeline<T> then(Pipeline<T> next) {
        return input -> next.process(this.process(input));
    }
}
public class App {
    public static void main(String[] args) {
        Pipeline<String> trim     = s -> s.strip();
        Pipeline<String> lower    = s -> s.toLowerCase();
        Pipeline<String> spaces   = s -> s.replace(" ", "_");

        Pipeline<String> pipeline = trim.then(lower).then(spaces);

        System.out.println("Processed: '" + pipeline.process("  Hello World  ") + "'");
        System.out.println("Processed: '" + pipeline.process("  AISHA and Raj  ") + "'");
    }
}

