import java.util.*;
import java.util.stream.*;
interface Repository<T, ID> {
    Optional<T> findById(ID id);
    List<T> findAll();
    T save(T entity);
    long count();
}
interface Mapper<S, T> {
    T mapTo(S source);
    S mapFrom(T target);
    default List<T> mapAllTo(List<S> src) {
        return src.stream().map(this::mapTo).collect(Collectors.toList());
    }
}
class User { int id; String name, email; User(int i, String n, String e) { id=i; name=n; email=e; } }
class UserDto { String name, email; UserDto(String n, String e) { name=n; email=e; }
    public String toString() { return "UserDto{" + name + ", " + email + "}"; }
}
class UserRepository implements Repository<User, Integer> {
    Map<Integer, User> store = new HashMap<>();
    int nextId = 1;
    public Optional<User> findById(Integer id) { return Optional.ofNullable(store.get(id)); }
    public List<User> findAll() { return new ArrayList<>(store.values()); }
    public User save(User u) { if (u.id==0) u.id=nextId++; store.put(u.id, u); return u; }
    public long count() { return store.size(); }
}
class UserMapper implements Mapper<User, UserDto> {
    public UserDto mapTo(User u) { return new UserDto(u.name, u.email); }
    public User mapFrom(UserDto d) { return new User(0, d.name, d.email); }
}
class UserService {
    private Repository<User, Integer> repo;
    private Mapper<User, UserDto> mapper;
    UserService(Repository<User,Integer> r, Mapper<User,UserDto> m) { repo=r; mapper=m; }

    User createUser(UserDto dto) {
        if (dto.name == null || dto.name.isBlank()) throw new IllegalArgumentException("Name required");
        User user = mapper.mapFrom(dto);
        return repo.save(user);
    }
    Optional<UserDto> getUser(int id) { return repo.findById(id).map(mapper::mapTo); }
    List<UserDto> listAll() { return mapper.mapAllTo(repo.findAll()); }
}
public class App {
    public static void main(String[] args) {
        UserService svc = new UserService(new UserRepository(), new UserMapper());
        User u1 = svc.createUser(new UserDto("Aisha", "aisha@x.com"));
        svc.createUser(new UserDto("Raj", "raj@x.com"));
        System.out.println("Created: " + u1.name + " (id=" + u1.id + ")");
        System.out.println("Get 1: " + svc.getUser(1).orElse(null));
        System.out.println("Get 99: " + svc.getUser(99).map(Object::toString).orElse("User not found"));
        System.out.println("List: " + svc.listAll());
    }
}

