exercises.expected_solution:
import java.util.*;
import java.util.stream.*;
interface Entity<ID> { ID getId(); void setId(ID id); }
interface Repository<T extends Entity<ID>, ID> {
    Optional<T> findById(ID id);
    List<T> findAll();
    T save(T e);
    void delete(T e);
    default boolean exists(ID id) { return findById(id).isPresent(); }
    default long count() { return findAll().size(); }
}
@FunctionalInterface interface Validator<T> {
    boolean isValid(T item);
    default Validator<T> and(Validator<T> other) { return item -> isValid(item) && other.isValid(item); }
}
interface Mapper<S, T> {
    T mapTo(S source);
    default List<T> mapAllTo(List<S> sources) {
        return sources.stream().map(this::mapTo).collect(Collectors.toList());
    }
}
class InMemoryRepository<T extends Entity<ID>, ID> implements Repository<T, ID> {
    private Map<ID, T> store = new HashMap<>();
    public Optional<T> findById(ID id) { return Optional.ofNullable(store.get(id)); }
    public List<T> findAll()           { return new ArrayList<>(store.values()); }
    public T save(T entity)            { store.put(entity.getId(), entity); return entity; }
    public void delete(T entity)       { store.remove(entity.getId()); }
}
class Employee implements Entity<Integer> {
    private Integer id; String name; double salary;
    Employee(Integer i, String n, double s) { id=i; name=n; salary=s; }
    public Integer getId() { return id; } public void setId(Integer i) { id=i; }
    public String toString() { return name; }
}
class Product implements Entity<String> {
    private String id; String name; double price;
    Product(String i, String n, double p) { id=i; name=n; price=p; }
    public String getId() { return id; } public void setId(String i) { id=i; }
    public String toString() { return name; }
}
public class App {
    public static void main(String[] args) {
        // Employee repository
        InMemoryRepository<Employee, Integer> empRepo = new InMemoryRepository<>();
        empRepo.save(new Employee(1, "Aisha", 95000));
        empRepo.save(new Employee(2, "Raj", 72000));
        System.out.println("Employee count: " + empRepo.count());

        // Product repository
        InMemoryRepository<Product, String> prodRepo = new InMemoryRepository<>();
        prodRepo.save(new Product("P01","Mouse",799));
        prodRepo.save(new Product("P02","Keyboard",1999));
        prodRepo.save(new Product("P03","USB Hub",499));
        System.out.println("Product count: " + prodRepo.count());

        // Exists (default method)
        System.out.println("Employee Aisha exists: " + empRepo.exists(1));

        // Validator
        Validator<Product> nonBlankName = p -> p.name != null && !p.name.isBlank();
        Validator<Product> positivePrice = p -> p.price > 0;
        Validator<Product> fullValidator = nonBlankName.and(positivePrice);
        Product invalid = new Product("P99", "", 100);
        if (!fullValidator.isValid(invalid)) System.out.println("Product invalid: Name cannot be blank");

        // Mapper
        Mapper<Employee, String> empToUpper = e -> e.name + "→" + e.name.toUpperCase();
        System.out.println("All employees mapped: " + empToUpper.mapAllTo(empRepo.findAll()));
    }
}
